    PacketHeader header;
    header.version = header_span[0];
    header.flags = header_span[1];
    // Assuming little-endian byte order for packet_id (network byte order)
    header.packet_id = static_cast<uint16_t>(header_span[2]) | 
                       (static_cast<uint16_t>(header_span[3]) << 8);

