```cpp
#include <hexi/shared.h>
#include <cstring>
#include <cstddef>

using namespace hexi::detail;

bool check_regions_overlap(const void* src, std::size_t src_len, const void* dst, std::size_t dst_len) {
    // Handle edge cases: null pointers or zero-length regions don't overlap
    if (!src || !dst || src_len == 0 || dst_len == 0) {
        return false;
    }

    // Convert pointers to unsigned integer addresses for safe comparison
    const auto src_start = reinterpret_cast<std::uintptr_t>(src);
    const auto src_end = src_start + src_len;
    const auto dst_start = reinterpret_cast<std::uintptr_t>(dst);
    const auto dst_end = dst_start + dst_len;

    // Two regions overlap if:
    // - src starts before dst ends AND
    // - dst starts before src ends
    return (src_start < dst_end) && (dst_start < src_end);
}

bool safe_memory_copy(void* destination, const void* source, std::size_t length) {
    // Handle null pointer cases
    if (!destination || !source) {
        return false;
    }

    // Zero-length copy is trivially safe and successful
    if (length == 0) {
        return true;
    }

    // Check for overlap between source and destination
    if (check_regions_overlap(source, length, destination, length)) {
        // Regions overlap - not safe for memcpy
        return false;
    }

    // No overlap detected - safe to copy
    std::memcpy(destination, source, length);
    return true;
}
```

