std::size_t write_multiple_chunks(const std::vector<std::vector<uint8_t>>& chunks) {
    // Calculate total size needed
    std::size_t total_size = 0;
    for (const auto& chunk : chunks) {
        total_size += chunk.size();
    }

    // Create a buffer with enough capacity
    std::vector<uint8_t> buffer;
    buffer.resize(total_size);

    // Create write adaptor
    hexi::pmc::buffer_write_adaptor writer(buffer);

    // Write each chunk
    for (const auto& chunk : chunks) {
        if (chunk.empty()) {
            continue;
        }

        // Check available space before writing
        std::size_t free_space = writer.free();

        // Ensure we have enough space
        if (free_space >= chunk.size()) {
            // Write the chunk
            writer.write(chunk.data(), chunk.size());
        }
    }

    // Return the total size written
    return writer.size();
}

std::vector<uint8_t> read_partial_data(const std::vector<uint8_t>& buffer, std::size_t chunk_size) {
    // Create read adaptor
    hexi::pmc::buffer_read_adaptor reader(buffer);

    // Result vector to store all read data
    std::vector<uint8_t> result;
    result.reserve(buffer.size());

    // Read until buffer is empty
    while (reader.size() > 0) {
        // Check remaining data with size()
        std::size_t remaining = reader.size();

        // Determine how much to read (chunk_size or remaining)
        std::size_t to_read = std::min(chunk_size, remaining);

        // Temporary buffer for this chunk
        std::vector<uint8_t> temp(to_read);

        // Read the chunk (partial read)
        reader.read(temp.data(), to_read);

        // Append to result
        result.insert(result.end(), temp.begin(), temp.end());
    }

    return result;
}

